import { IInventar } from './../_interface/inventar';
import {
  AfterViewInit,
  Component,
  OnInit,
  ViewChild,
  ElementRef,
  inject,
} from '@angular/core';
import {
  FormControl,
  FormGroup,
  Validators,
  FormsModule,
  ReactiveFormsModule,
} from '@angular/forms';
import { GlobalDataService } from 'src/app/_service/global-data.service';
import { MatCardModule } from '@angular/material/card';
import { MatFormField, MatLabel, MatError } from '@angular/material/form-field';
import { NgStyle } from '@angular/common';
import { MatButton } from '@angular/material/button';
import { MatInputModule } from '@angular/material/input';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { Router } from '@angular/router';
import { HeaderComponent } from '../_template/header/header.component';
import { FormatService } from '../helpers/format.service';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatIcon } from '@angular/material/icon';
import { MatPaginator, MatPaginatorModule } from '@angular/material/paginator';
import { MatSort, MatSortModule } from '@angular/material/sort';

@Component({
  selector: 'app-inventar',
  imports: [
    HeaderComponent,
    MatCardModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormField,
    MatLabel,
    MatButton,
    MatInputModule,
    MatError,
    NgStyle,
    MatAutocompleteModule,
    MatTableModule,
    MatSortModule,
    MatPaginatorModule,
    MatIcon
  ],
  templateUrl: './inventar.component.html',
  styleUrl: './inventar.component.sass',
})
export class InventarComponent implements OnInit, AfterViewInit {
  @ViewChild('fotoUpload', { static: false }) fotoRef!: ElementRef<HTMLInputElement>;
  @ViewChild(MatPaginator) paginator?: MatPaginator;
  @ViewChild(MatSort) sort?: MatSort;

  globalDataService = inject(GlobalDataService);
  formatService = inject(FormatService);
  router = inject(Router);

  title = 'Inventar';
  modul = 'inventar';

  inventarArray: IInventar[] = [];
  breadcrumb: any = [];
  dataSource = new MatTableDataSource<IInventar>(this.inventarArray);
  sichtbareSpalten: string[] = ['bezeichnung', 'anzahl', 'lagerort', 'actions'];

  btnText = 'Bild auswählen';
  fileName = '';
  filePfad = '';
  fileFound = false;
  btnUploadStatus = false;

  formModul = new FormGroup({
    id: new FormControl<string | ''>(''),
    bezeichnung: new FormControl<string>('', { nonNullable: true, validators: [Validators.required] }),
    anzahl: new FormControl<number>(0),
    lagerort: new FormControl<string>(''),
    notiz: new FormControl<string>(''),
    // nur für Anzeige/Modal – NICHT ans Backend senden
    foto_url: new FormControl<string>(''),
  });

  ngAfterViewInit(): void {
    this.bindTableControls();
  }

  ngOnInit(): void {
    sessionStorage.setItem('PageNumber', '2');
    sessionStorage.setItem('Page2', 'INV');
    this.breadcrumb = this.globalDataService.ladeBreadcrumb();

    this.formModul.disable();

    this.globalDataService.get(this.modul).subscribe({
      next: (erg: any) => {
        try {
          this.inventarArray = this.convertNewsDate(erg) as IInventar[];
          this.dataSource.data = this.inventarArray;
          this.bindTableControls();
        } catch (e: any) {
          this.globalDataService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  /** Datei aus dem ViewChild-input holen */
  private getSelectedFile(): File | null {
    const el = this.fotoRef?.nativeElement;
    return el?.files && el.files.length ? el.files[0] : null;
  }

  /** Server-Datum ins gewünschte Anzeigeformat bringen */
  convertNewsDate(data: any): any[] {
    for (let i = 0; i < data.length; i++) {
      const created_at = String(data[i].created_at).split('T');
      const created_at_date = created_at[0];
      const created_at_time = created_at[1]?.split(':') ?? [];
      data[i].created_at = created_at_date + '_' + created_at_time[0] + ':' + created_at_time[1];

      const updated_at = String(data[i].updated_at).split('T');
      const updated_at_date = updated_at[0];
      const updated_at_time = updated_at[1]?.split(':') ?? [];
      data[i].updated_at = updated_at_date + '_' + updated_at_time[0] + ':' + updated_at_time[1];
    }
    return data;
  }

  datenLoeschen(): void {
    const id = this.formModul.controls['id'].value!;
    this.globalDataService.delete(this.modul, id).subscribe({
      next: (erg: any) => {
        try {
          this.inventarArray = this.inventarArray.filter(n => n.id !== id);
          this.dataSource.data = this.inventarArray;
          this.resetFormNachAktion();
          this.globalDataService.erstelleMessage('success', 'Inventar erfolgreich gelöscht!');
        } catch (e: any) {
          this.globalDataService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => this.globalDataService.errorAnzeigen(error)
    });
  }

  auswahlBearbeiten(element: any): void {
    if (element.id === 0) {
      return;
    }
    const abfrageUrl = `${this.modul}/${element.id}`;
    this.globalDataService.get(abfrageUrl).subscribe({
      next: (erg: any) => {
        try {
          let details: IInventar = erg;
          this.formModul.enable();
          this.btnUploadStatus = true;

          // UI-Status für bestehendes Bild
          if ((details as any).foto_url) {
            this.btnText = 'Bild ersetzen';
            const parts = (details as any).foto_url.split('/');
            this.fileName = parts[parts.length - 1];
            this.fileFound = true;
            this.filePfad = (details as any).foto_url;
          } else {
            this.btnText = 'Bild auswählen';
            this.fileName = '';
            this.fileFound = false;
            this.filePfad = '';
          }

          this.formModul.setValue({
            id: details.id!,
            bezeichnung: details.bezeichnung,
            anzahl: details.anzahl,
            lagerort: details.lagerort,
            notiz: details.notiz,
            foto_url: ''
          });
        } catch (e: any) {
          this.globalDataService.erstelleMessage('error', e);
        }
      },
      error: (error: any) => this.globalDataService.errorAnzeigen(error)
    });
  }

  abbrechen(): void {
    this.globalDataService.erstelleMessage('info', 'News nicht gespeichert!');
    this.router.navigate(['/inventar']);
  }

  neueDetails(): void {
    this.formModul.enable();
    this.btnUploadStatus = true;
    this.btnText = 'Bild auswählen';
    this.fileName = '';
    this.filePfad = '';
    this.fileFound = false;
    this.formModul.patchValue({ id: '', bezeichnung: '', anzahl: 0, lagerort: '', notiz: '', foto_url: '' });

    // Datei-Auswahl im Input zurücksetzen
    if (this.fotoRef?.nativeElement) {
      this.fotoRef.nativeElement.value = '';
    }
  }

  datenSpeichern(): void {
    const idValue = this.formModul.controls['id'].value || '';
    const bezeichnung = this.formModul.controls['bezeichnung'].value!;
    const anzahl = this.formModul.controls['anzahl'].value!;
    const lagerort = this.formModul.controls['lagerort'].value!;
    const notiz = this.formModul.controls['notiz'].value!;
    const file = this.getSelectedFile();

    if (!idValue) {
      // CREATE
      if (file) {
        const fd = new FormData();
        fd.append('bezeichnung', bezeichnung);
        fd.append('anzahl', anzahl.toString());
        fd.append('lagerort', lagerort);
        fd.append('notiz', notiz);
        fd.append('foto', file, file.name || 'upload.png');

        this.globalDataService.post(this.modul, fd, true).subscribe({
          next: (erg: any) => {
            try {
              const newMask: IInventar = erg;
              this.inventarArray.push(newMask);
              this.inventarArray = this.globalDataService.arraySortByKey(this.inventarArray, 'bezeichnung');
              this.dataSource.data = this.inventarArray;
              this.bindTableControls();
              this.resetFormNachAktion();
              this.globalDataService.erstelleMessage('success', 'Inventar erfolgreich gespeichert!');
            } catch (e: any) {
              this.globalDataService.erstelleMessage('error', e);
            }
          },
          error: (error: any) => this.globalDataService.errorAnzeigen(error)
        });
      } else {
        // JSON ohne Bild
        this.globalDataService.post(this.modul, { bezeichnung, anzahl, lagerort, notiz }, false).subscribe({
          next: (erg: any) => {
            try {
              const newMask: IInventar = erg;
              this.inventarArray.push(newMask);
              this.inventarArray = this.globalDataService.arraySortByKey(this.inventarArray, 'bezeichnung');
              this.dataSource.data = this.inventarArray;
              this.bindTableControls();
              this.resetFormNachAktion();
              this.globalDataService.erstelleMessage('success', 'Inventar erfolgreich gespeichert!');
            } catch (e: any) {
              this.globalDataService.erstelleMessage('error', e);
            }
          },
          error: (error: any) => this.globalDataService.errorAnzeigen(error)
        });
      }
    } else {
      // UPDATE
      if (file) {
        const fd = new FormData();
        fd.append('bezeichnung', bezeichnung);
        fd.append('anzahl', anzahl.toString());
        fd.append('lagerort', lagerort);
        fd.append('notiz', notiz);
        fd.append('foto', file, file.name || 'upload.png');

        this.globalDataService.patch(this.modul, idValue, fd, true).subscribe({
          next: (erg: any) => {
            try {
              const updated: any = erg;
              this.inventarArray = this.inventarArray
                .map(m => m.id === updated.id ? updated : m)
                .sort((a, b) => a.bezeichnung - b.bezeichnung);

              this.dataSource.data = this.inventarArray;
              this.bindTableControls();
              this.resetFormNachAktion();
              this.globalDataService.erstelleMessage('success', 'Inventar erfolgreich geändert!');
            } catch (e: any) {
              this.globalDataService.erstelleMessage('error', e);
            }
          },
          error: (error: any) => this.globalDataService.errorAnzeigen(error)
        });
      } else {
        // Nur Text/Titel ändern (JSON)
        this.globalDataService.patch(this.modul, idValue, { bezeichnung, anzahl, lagerort, notiz }, false).subscribe({
          next: (erg: any) => {
            try {
              const updated: any = erg;
              this.inventarArray = this.inventarArray
                .map(m => m.id === updated.id ? updated : m)
                .sort((a, b) => a.bezeichnung - b.bezeichnung);

              this.dataSource.data = this.inventarArray;
              this.bindTableControls();
              this.resetFormNachAktion();
              this.globalDataService.erstelleMessage('success', 'Inventar erfolgreich geändert!');
            } catch (e: any) {
              this.globalDataService.erstelleMessage('error', e);
            }
          },
          error: (error: any) => this.globalDataService.errorAnzeigen(error)
        });
      }
    }
  }

  onFotoSelected(event: Event): void {
    const file = this.getSelectedFile();
    if (!file) {
      this.fileFound = false;
      this.fileName = '';
      return;
    }
    const sizeKB = Math.round(file.size / 1024);
    if (sizeKB >= this.globalDataService.MaxUploadSize) {
      this.fileFound = false;
      this.fileName = '';
      const maxMB = this.globalDataService.MaxUploadSize / 1024;
      this.globalDataService.erstelleMessage('error', `Foto darf nicht größer als ${maxMB}MB sein!`);
      // Input leeren
      if (this.fotoRef?.nativeElement) this.fotoRef.nativeElement.value = '';
    } else {
      this.fileFound = true;
      this.fileName = file.name;
    }
  }

  openModal(): void {
    const modal: any = document.getElementById('myModal');
    if (modal) modal.style.display = 'block';
  }

  closeModal(): void {
    const modal: any = document.getElementById('myModal');
    if (modal) modal.style.display = 'none';
  }

  /** Nach Create/Update Formular, UI & File-Input zurücksetzen */
  private resetFormNachAktion(): void {
    this.formModul.reset({ id: '', bezeichnung: '', anzahl: 0, lagerort: '', notiz: '', foto_url: '' });
    this.formModul.disable();
    this.btnUploadStatus = false;
    this.btnText = 'Bild auswählen';
    this.fileName = '';
    this.filePfad = '';
    this.fileFound = false;
    // Datei im Input löschen
    if (this.fotoRef?.nativeElement) {
      this.fotoRef.nativeElement.value = '';
    }
  }

  private bindTableControls(): void {
    if (this.paginator) {
      this.dataSource.paginator = this.paginator;
    }
    if (this.sort) {
      this.dataSource.sort = this.sort;
    }
  }
}

import { Component, OnInit, Output, EventEmitter, inject } from '@angular/core';

import { FormControl, FormGroup, Validators, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { GlobalDataService } from 'src/app/_service/global-data.service';
import { IKonfiguration } from 'src/app/_interface/konfiguration';
import { MatCardModule } from '@angular/material/card';
import { MatButton } from '@angular/material/button';
import { MatFormField, MatLabel, MatError } from '@angular/material/form-field';
import { MatInput } from '@angular/material/input';
import { MatIconModule } from '@angular/material/icon';
import { environment } from "src/environments/environment";
import { Router } from '@angular/router';
import { HeaderComponent } from '../_template/header/header.component';
import { MatChipsModule } from '@angular/material/chips';
import { MatOption, MatSelect } from '@angular/material/select';
import { MatTableModule } from '@angular/material/table';

@Component({
    selector: 'app-konfiguration',
    templateUrl: './konfiguration.component.html',
    styleUrls: ['./konfiguration.component.sass'],
    imports: [HeaderComponent, MatCardModule, FormsModule, ReactiveFormsModule, MatButton, MatFormField, MatLabel, MatInput, MatError, MatIconModule, MatChipsModule, MatSelect, MatOption, MatTableModule]
})
export class KonfigurationComponent implements OnInit {
  globalDataService = inject(GlobalDataService);
  router = inject(Router);
  breadcrumb: any = [];

  title = "Aktive Rollen";
  title2 = "Stammdaten";
  title3 = "Backup & Wiederherstellen";
  modul = "users/rolle";
  modul2 = "konfiguration";

  @Output() breadcrumbout = new EventEmitter<any[]>();

  rollen: any = []
  backups: any = [];
  backupColumns: string[] = ['name', 'actions'];
  cleanupColumns: string[] = ['target', 'filename'];
  backup_msg = "";
  cleanupTarget: 'all' | 'news' | 'inventar' = 'all';
  cleanupRunning = false;
  cleanupSummary = '';
  cleanupFiles: Array<{ target: string; filename: string }> = [];

  formRolle = new FormGroup({
    rolle: new FormControl('')
  });

  formKonfig = new FormGroup({
    id: new FormControl(''),
    fw_nummer: new FormControl('', Validators.required),
    fw_name: new FormControl('', Validators.required),
    fw_street: new FormControl('', Validators.required),
    fw_plz: new FormControl('', Validators.required),
    fw_ort: new FormControl('', Validators.required),
    fw_email: new FormControl('', Validators.required),
    fw_telefon: new FormControl('', Validators.required),
    fw_kdt: new FormControl('', Validators.required),
    fw_webseite: new FormControl('', Validators.required),
    fw_konto: new FormControl('', Validators.required),
    fw_iban: new FormControl('', Validators.required),
    fw_bic: new FormControl('', Validators.required)
  });

  ngOnInit(): void {
    sessionStorage.setItem("PageNumber", "2");
    sessionStorage.setItem("Page2", "V_KO");
    this.breadcrumb = this.globalDataService.ladeBreadcrumb();
    this.formRolle.disable();
    this.formKonfig.disable();

    this.globalDataService.get(this.modul2).subscribe({
      next: (erg: any) => {
        try {
          this.formRolle.enable();
          this.formKonfig.enable();

          if (erg.main.length > 0){
            const details: IKonfiguration = erg.main[0];
            this.formKonfig.setValue({
              id: details.id,
              fw_nummer: details.fw_nummer,
              fw_name: details.fw_name,
              fw_street: details.fw_street,
              fw_plz: details.fw_plz,
              fw_ort: details.fw_ort,
              fw_email: details.fw_email,
              fw_telefon: details.fw_telefon,
              fw_kdt: details.fw_kdt,
              fw_webseite: details.fw_webseite,
              fw_konto: details.fw_konto,
              fw_iban: details.fw_iban,
              fw_bic: details.fw_bic
            })
          }
          this.rollen = erg.rollen;
          this.backups = this.convertBackups(erg.backups);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  rolleSpeichern(): void {
    const object = this.formRolle.value;
    const rolle_neu = object.rolle;

    const post = {
      "key": rolle_neu,
      "verbose_name": rolle_neu
    }


    this.globalDataService.post(this.modul, post, false).subscribe({
      next: (erg: any) => {
        try {
          this.formRolle.reset();
          if (!this.rollen.find((r: any) => r.key === erg.key)) {
            this.rollen.push(erg);
          }
          this.globalDataService.erstelleMessage("success","Rolle erfolgreich gespeichert!");
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  rolleLoeschen(rolle: any): void {
    const id = rolle.id;
    this.globalDataService.delete(this.modul, id).subscribe({
      next: (erg: any) => {
        try {
          this.rollen = this.rollen.filter((r: any) => r.id !== id);
          this.globalDataService.erstelleMessage("success", "Rolle erfolgreich gelöscht!");
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  konfigSpeichern(): void {
    const object = this.formKonfig.value;

    const idValue = this.formKonfig.controls["id"].value;
    if (idValue === '' || idValue === null) {
      this.globalDataService.post(this.modul2, object, false).subscribe({
        next: (erg: any) => {
          try {
            const details: IKonfiguration = erg;
            this.formKonfig.setValue({
              id: details.id,
              fw_nummer: details.fw_nummer,
              fw_name: details.fw_name,
              fw_street: details.fw_street,
              fw_plz: details.fw_plz,
              fw_ort: details.fw_ort,
              fw_email: details.fw_email,
              fw_telefon: details.fw_telefon,
              fw_kdt: details.fw_kdt,
              fw_webseite: details.fw_webseite,
              fw_konto: details.fw_konto,
              fw_iban: details.fw_iban,
              fw_bic: details.fw_bic
            })
            this.globalDataService.erstelleMessage("success","Konfiguration erfolgreich gespeichert!");
          } catch (e: any) {
            this.globalDataService.erstelleMessage("error", e);
          }
        },
        error: (error: any) => {
          this.globalDataService.errorAnzeigen(error);
        }
      });
    } else {
      this.globalDataService.patch(this.modul2, idValue, object, false).subscribe({
        next: (erg: any) => {
          try {
            const details: IKonfiguration = erg;
            this.formKonfig.setValue({
              id: details.id,
              fw_nummer: details.fw_nummer,
              fw_name: details.fw_name,
              fw_street: details.fw_street,
              fw_plz: details.fw_plz,
              fw_ort: details.fw_ort,
              fw_email: details.fw_email,
              fw_telefon: details.fw_telefon,
              fw_kdt: details.fw_kdt,
              fw_webseite: details.fw_webseite,
              fw_konto: details.fw_konto,
              fw_iban: details.fw_iban,
              fw_bic: details.fw_bic
            })
            this.globalDataService.erstelleMessage("success","Konfiguration erfolgreich geändert!");
          } catch (e: any) {
            this.globalDataService.erstelleMessage("error", e);
          }
        },
        error: (error: any) => {
          this.globalDataService.errorAnzeigen(error);
        }
      });
    }
  }

  backupImport(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.post("backup/restore", object, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.globalDataService.erstelleMessage("success",this.backup_msg);
          sessionStorage.clear();
          document.cookie.split('; ').forEach(cookie => {
            const [name] = cookie.split('=');
            document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
          });
          this.router.navigate(['/login']);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupErstellen(): void {
    this.globalDataService.post("backup", {}, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.backups = this.convertBackups(erg.backups);
          this.globalDataService.erstelleMessage("success",this.backup_msg);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupDownload(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.postBlob("backup/file", object).subscribe({
      next: (blob: Blob) => {
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = backup_name.name;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  backupLoeschen(backup_name: any): void {
    const object = {
      "backup": backup_name.name
    }

    this.globalDataService.post("backup/delete", object, false).subscribe({
      next: (erg: any) => {
        try {
          this.backup_msg = erg.msg;
          this.backups = this.convertBackups(erg.backups);
          this.globalDataService.erstelleMessage("success",this.backup_msg);
        } catch (e: any) {
          this.globalDataService.erstelleMessage("error", e);
        }
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
      }
    });
  }

  mediaCleanup(deleteFiles: boolean): void {
    if (this.cleanupRunning) {
      return;
    }

    this.cleanupRunning = true;
    const payload = {
      target: this.cleanupTarget,
      delete: deleteFiles,
    };

    this.globalDataService.cleanupOrphanMedia(payload).subscribe({
      next: (erg: any) => {
        const summary = erg?.summary ?? {};
        const orphanCount = summary.orphan ?? 0;
        const deletedCount = erg?.deleted ?? 0;
        this.cleanupSummary = `Ergebnis: ${orphanCount} verwaist gefunden, ${deletedCount} gelöscht.`;
        this.cleanupFiles = [];

        for (const item of (erg?.items ?? [])) {
          for (const orphan of (item?.orphans ?? [])) {
            this.cleanupFiles.push({
              target: item.target,
              filename: orphan,
            });
          }
        }

        const message = `Medien bereinigt: ${deletedCount} gelöscht, ${orphanCount} verwaist gefunden.`;
        this.globalDataService.erstelleMessage('success', message);
        this.cleanupRunning = false;
      },
      error: (error: any) => {
        this.globalDataService.errorAnzeigen(error);
        this.cleanupRunning = false;
      }
    });
  }

  convertBackups(backup_array:any ): any {
    const version = environment.version;
    let data = [];
    for (let i = 0; i < backup_array.length; i++) {
      const file = backup_array[i];
      let backup_version = file.split('_');
      backup_version = backup_version[1];

      if (backup_version == version || backup_version == 'test') {
        const dict = {
          "name": file,
        }
        data.push(dict);
      }
    }
    data = this.globalDataService.arraySortByKeyDesc(data, "name");
    return data;
  }
}

